package parsers

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/petrarca/tech-stack-analyzer/internal/types"
)

// These tests run the graph producers against REAL lockfiles generated by the
// actual package managers (cargo, npm, pnpm, uv, bundler, composer, mix,
// poetry) from well-known PUBLIC packages -- see testdata/lockfiles/. They
// verify the parsers handle authentic tool output (not just hand-written
// fixtures) and that the expected package-to-package edges are produced.
//
// The fixtures contain only public OSS packages (serde, express, requests,
// sinatra, monolog, flask, plug, ...). No proprietary or internal package
// names appear in them.

func readFixture(t *testing.T, name string) []byte {
	t.Helper()
	b, err := os.ReadFile(filepath.Join("testdata", "lockfiles", name))
	if err != nil {
		t.Fatalf("read fixture %s: %v", name, err)
	}
	return b
}

func edgeSetFromGraph(g LockGraph) map[string]bool {
	out := map[string]bool{}
	for _, e := range g.Edges {
		out[e.From+"->"+e.To] = true
	}
	return out
}

func assertEdges(t *testing.T, got map[string]bool, want ...string) {
	t.Helper()
	for _, w := range want {
		if !got[w] {
			t.Errorf("missing edge %q (have %d edges)", w, len(got))
		}
	}
}

func TestRealLockfile_Cargo(t *testing.T) {
	g := ParseCargoLockGraph(GraphInput{Lockfile: readFixture(t, "Cargo.lock"), Mode: types.DependencyGraphFull})
	got := edgeSetFromGraph(g)
	// serde feature=derive pulls in serde_derive; macro stack proc-macro2/quote/syn.
	assertEdges(t, got,
		"fixture@0.1.0->serde@1.0.228",
		"fixture@0.1.0->serde_json@1.0.150",
		"serde@1.0.228->serde_derive@1.0.228",
		"quote@1.0.45->proc-macro2@1.0.106",
	)
}

func TestRealLockfile_Pnpm(t *testing.T) {
	g := ParsePnpmLockGraph(GraphInput{Lockfile: readFixture(t, "pnpm-lock.yaml"), Mode: types.DependencyGraphFull})
	got := edgeSetFromGraph(g)
	// express 5.2.1 is the root dep; it pulls in router/vary/cookie-signature.
	assertEdges(t, got,
		"express@5.2.1->router@2.2.0",
		"express@5.2.1->vary@1.1.2",
		"express@5.2.1->cookie-signature@1.2.2",
	)
}

func TestRealLockfile_Uv(t *testing.T) {
	g := ParseUvLockGraph(GraphInput{Lockfile: readFixture(t, "uv.lock"), Mode: types.DependencyGraphFull})
	got := edgeSetFromGraph(g)
	// requests -> its classic transitive set.
	assertEdges(t, got,
		"requests@2.34.2->urllib3@2.7.0",
		"requests@2.34.2->certifi@2026.5.20",
		"requests@2.34.2->idna@3.18",
	)
}

