func TestRealLockfile_NpmV3(t *testing.T) {
	g := ParsePackageLockGraph(GraphInput{Lockfile: readFixture(t, "package-lock.json"), Mode: types.DependencyGraphFull})
	got := edgeSetFromGraph(g)
	// express resolves transitives via node_modules nearest-wins.
	assertEdges(t, got,
		"express@5.2.1->router@2.2.0",
		"express@5.2.1->vary@1.1.2",
	)
}

// TestRealLockfile_AllParseWithoutPanic is a smoke test: every real fixture
// must parse in every mode without panicking and never emit a malformed node id.
func TestRealLockfile_AllModesNoMalformed(t *testing.T) {
	cases := []struct {
		file string
		fn   func(GraphInput) LockGraph
	}{
		{"Cargo.lock", ParseCargoLockGraph},
		{"package-lock.json", ParsePackageLockGraph},
		{"pnpm-lock.yaml", ParsePnpmLockGraph},
		{"uv.lock", ParseUvLockGraph},
		{"Gemfile.lock", ParseGemfileLockGraph},
		{"composer.lock", ParseComposerLockGraph},
		{"poetry.lock", ParsePoetryLockGraph},
		{"mix.lock", ParseMixLockGraph},
	}
	modes := []types.DependencyGraphMode{
		types.DependencyGraphOff, types.DependencyGraphDirect, types.DependencyGraphFull,
	}
	for _, c := range cases {
		content := readFixture(t, c.file)
		for _, m := range modes {
			g := c.fn(GraphInput{Lockfile: content, Mode: m})
			if m == types.DependencyGraphOff && len(g.Edges) != 0 {
				t.Errorf("%s off mode: expected 0 edges, got %d", c.file, len(g.Edges))
			}
			for _, e := range g.Edges {
				if e.From == "" || e.To == "" {
					t.Errorf("%s: empty edge endpoint %+v", c.file, e)
				}
				// 'to' must carry a version: "name@version" (1 '@') or a scoped
				// npm package "@scope/name@version" (2 '@'). 'from' may be '.'.
				if at := countAt(e.To); at < 1 || at > 2 {
					t.Errorf("%s: malformed 'to' node %q", c.file, e.To)
				}
			}
		}
	}
}

func countAt(s string) int {
	n := 0
	for _, r := range s {
		if r == '@' {
			n++
		}
	}
	return n
}
